if (!function_exists('sd_t')) {
  function sd_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('sd_h')) {
  function sd_h($key, $fallback = '') { return htmlspecialchars((string) sd_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('sd_js')) {
  function sd_js($key, $fallback = '') { return json_encode(sd_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom = date('Y-m-01');
$defaultTo = date('Y-m-d');
$customers = $db->query("SELECT kode_penerima,nama FROM penerima ORDER BY nama");
$invoices = $db->query("
  SELECT si.id_sales,si.no_sales_invoice,si.invoice_date,si.valuta,si.gross_amount,p.nama customer_name
  FROM sales_invoice si
  LEFT JOIN penerima p ON p.kode_penerima=si.bill_to
  WHERE si.billing_status='POSTED'
    AND si.billing_type NOT IN ('CM','DM')
  ORDER BY si.invoice_date DESC,si.id_sales DESC
  LIMIT 300
");
$kpi = $db->fetch("
  SELECT COUNT(*) doc_count,
         COALESCE(SUM(CASE WHEN billing_type='DM' THEN gross_amount ELSE 0 END),0) debit_total,
         COALESCE(SUM(CASE WHEN billing_type='CM' THEN gross_amount ELSE 0 END),0) credit_total,
         COALESCE(SUM(CASE WHEN billing_status='CANCELLED' THEN 1 ELSE 0 END),0) cancelled_count
  FROM sales_invoice
  WHERE billing_type IN ('CM','DM')
    AND invoice_date BETWEEN ? AND ?
", array($defaultFrom,$defaultTo));
?>
