span class="glyphicon glyphicon-calendar"></span></span></div></div></div><div class="form-group"><label class="control-label col-lg-2">Reason Code</label><div class="col-lg-3"><select name="memo_reason_code" id="memo_reason_code" class="form-control"><option value="PRICE">Price Difference</option><option value="DISCOUNT">Additional Discount</option><option value="RETURN">Return / Claim</option><option value="FREIGHT">Freight / Charge</option><option value="TAX">Tax Correction</option><option value="OTHER">Other Adjustment</option></select></div><label class="control-label col-lg-2"><?=sd_h('sales_tax', 'Tax');?></label><div class="col-lg-2"><select name="tax" id="tax" class="form-control"><option value="1">PPN 11%</option><option value="0">Non PPN</option></select></div><label class="control-label col-lg-1"><?=sd_h('sales_currency', 'Currency');?></label><div class="col-lg-2"><input name="valuta" id="valuta" class="form-control" readonly></div></div><div class="form-group"><label class="control-label col-lg-2">Net Amount <span class="text-red">*</span></label><div class="col-lg-3"><input name="memo_amount" id="memo_amount" type="number" min="0" step="0.01" class="form-control text-right" required></div><label class="control-label col-lg-2">Reason Text</label><div class="col-lg-5"><input name="memo_reason_text" id="memo_reason_text" class="form-control" placeholder="Penjelasan singkat koreksi"></div></div><div class="row"><div class="col-sm-4"><div class="well well-sm"><span>DPP</span><div class="cdm-money" id="net_preview">0.00</div></div></div><div class="col-sm-4"><div class="well well-sm"><span>PPN</span><div class="cdm-money" id="tax_preview">0.00</div></div></div><div class="col-sm-4"><div class="well well-sm"><span>Grand Total</span><div class="cdm-money" id="gross_preview">0.00</div></div></div></div><div class="cdm-section">Notes & Signature</div><div class="form-group"><label class="control-label col-lg-2">Signed By</label><div class="col-lg-4"><input name="ttd" class="form-control" required></div><label class="control-label col-lg-2">Notes</label><div class="col-lg-4"><input name="catatan" class="form-control"></div></div><input type="hidden" id="original_gross_amount"><input type="hidden" name="bill_to" id="bill_to"><input type="hidden" name="ship_to" id="ship_to"><input type="hidden" name="no_sales_order" id="no_sales_order"><input type="hidden" name="nopo" id="nopo"></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=sd_h('common_close', 'Close');?></button><button type="submit" id="btn_save_memo" class="btn btn-warning" disabled><i class="fa fa-save"></i> Post Memo</button></div></form></div></div></div>
