<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function cdmNumber(v){v=parseFloat(v||0);return isNaN(v)?0:v;}function cdmFmt(v){return cdmNumber(v).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});}
function cdmError(m){$('.isi_warning_delete').text(m||<?=sd_js('sales_credit_debit_process_failed', 'Credit/Debit Memo failed to process.');?>);$('.error_data_delete').fadeIn();}
function cdmFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),customer:$('#filter_customer').val(),type:$('#filter_type').val(),status:$('#filter_status').val(),keyword:$('#filter_keyword').val()};}
function cdmQuery(){return $.param(cdmFilters());}
function recalcMemo(){var net=cdmNumber($('#memo_amount').val()),tax=$('#tax').val()==='1'?net*.11:0;$('#net_preview').text(cdmFmt(net));$('#tax_preview').text(cdmFmt(tax));$('#gross_preview').text(cdmFmt(net+tax));$('#btn_save_memo').prop('disabled',!$('#original_invoice_id').val()||net<=0);}
$(function(){if($.fn.datepicker){$('.cdm-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_customer,#filter_type,#filter_status,#memo_type,#original_invoice_id,#memo_reason_code,#tax').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_credit_debit_memo').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=sd_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'108px',targets:1}],ajax:{url:'<?=base_admin();?>modul/credit_debit_memo/credit_debit_memo_data.php',type:'post',data:function(d){$.extend(d,cdmFilters());},error:function(xhr){console.log(xhr.responseText);cdmError(<?=sd_js('sales_memo_load_failed', 'Memo data failed to load.');?>);}}});
$('#btn_filter_cdm').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#btn_reset_cdm').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_customer,#filter_type,#filter_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_cdm').click(function(){window.location='<?=base_admin();?>modul/credit_debit_memo/credit_debit_memo_action.php?act=excel&'+cdmQuery();});
function refreshNo(){ $.getJSON('<?=base_admin();?>modul/credit_debit_memo/credit_debit_memo_action.php?act=get_no',{type:$('#memo_type').val()},function(r){$('#no_sales_invoice').val(r.no||'');});}
$('#btn_add_memo').click(function(){$('#form_memo')[0].reset();$('.error_data').hide();$('#invoice_date').val('<?=date('Y-m-d');?>');$('#invoice_summary').hide().html('');$('#memo_type').val('CM').trigger('change');$('#original_invoice_id,#memo_reason_code,#tax').val('').trigger('change');$('#tax').val('1').trigger('change');$('#btn_save_memo').prop('disabled',true);refreshNo();recalcMemo();$('#modal_memo_form').modal('show');});
$('#memo_type').change(refreshNo);
$('#original_invoice_id').change(function(){var id=$(this).val();if(!id){$('#invoice_summary').hide();recalcMemo();return;}$.getJSON('<?=base_admin();?>modul/credit_debit_memo/credit_debit_memo_action.php?act=get_invoice',{id:id},function(r){if(r.status==='error'){Swal.fire('Error',r.error_message,'error');return;}$('#bill_to').val(r.bill_to);$('#ship_to').val(r.ship_to);$('#no_sales_order').val(r.no_sales_order);$('#nopo').val(r.nopo);$('#valuta').val(r.valuta);$('#tax').val(r.tax).trigger('change');$('#original_gross_amount').val(r.gross_amount);$('#invoice_summary').html(r.html).show();recalcMemo();});});
$('#memo_amount,#tax').on('keyup change',recalcMemo);
$('#form_memo').ajaxForm({dataType:'json',beforeSubmit:function(){recalcMemo();$('#loadnya').show();},success:function(res){$('#loadnya').hide();var ok=false,msg='';$.each(res||[],function(_,r){if(r.status==='good')ok=true;if(r.status==='error')msg=r.error_message;});if(ok){$('#modal_memo_form').modal('hide');Swal.fire('Success','Credit/Debit Memo berhasil diposting.','success');dt.draw(false);}else{$('.isi_warning').text(msg||<?=sd_js('sales_memo_save_failed', 'Memo failed to save.');?>);$('.error_data').fadeIn();}},error:function(xhr){$('#loadnya').hide();console.log(xhr.responseText);$('.isi_warning').text(<?=sd_js('sales_memo_save_failed', 'Memo failed to save.');?>);$('.error_data').fadeIn();}});
$(document).on('click','.btn-cdm-detail',function(){$.post('<?=base_admin();?>modul/credit_debit_memo/credit_debit_memo_action.php?act=detail',{id:$(this).data('id')},function(html){$('#cdm_detail_body').html(html);$('#modal_detail_cdm').modal('show');}).fail(function(){cdmError('Detail gagal dibuka.');});});
$(document).on('click','.btn-cdm-cancel',function(){var id=$(this).data('id');Swal.fire({title:'Cancel Memo?',input:'text',inputLabel:'Alasan cancel',inputPlaceholder:'Masukkan alasan',icon:'warning',showCancelButton:true,confirmButtonText:'Cancel Memo',inputValidator:function(v){if(!v)return 'Alasan wajib diisi';}}).then(function(r){if(!r.isConfirmed)return;$.post('<?=base_admin();?>modul/credit_debit_memo/credit_debit_memo_action.php?act=cancel',{id:id,reason:r.value},function(res){var ok=false,msg='';$.each(res||[],function(_,x){if(x.status==='good')ok=true;if(x.status==='error')msg=x.error_message;});if(ok){Swal.fire('Success','Memo berhasil dicancel.','success');dt.draw(false);}else Swal.fire('Error',msg||'Cancel gagal.','error');},'json').fail(function(xhr){console.log(xhr.responseText);Swal.fire('Error','Cancel gagal.','error');});});});
});
</script>
